Your intention to help users is good, but specific error messages create a serious security vulnerability called **account enumeration**. Attackers can determine which accounts exist in your system, enabling targeted attacks.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const db = require('./database');

const app = express();
app.use(express.json());

app.post('/api/login', async (req, res) => {
  const { email, password } = req.body;

  try {
    // VULNERABLE: First check if user exists
    const user = await db.query(
      'SELECT * FROM users WHERE email = $1',
      [email]
    );

    if (!user.rows.length) {
      // VULNERABLE: Different message reveals account doesn't exist
      return res.status(401).json({
        error: 'No account found with this email address'
      });
    }

    const validPassword = await bcrypt.compare(password, user.rows[0].password_hash);

    if (!validPassword) {
      // VULNERABLE: Different message reveals account EXISTS but wrong password
      return res.status(401).json({
        error: 'Incorrect password. Please try again.'
      });
    }

    // Login successful
    res.json({ token: generateToken(user.rows[0]) });

  } catch (error) {
    res.status(500).json({ error: 'Server error' });
  }
});
```

**Attack Payload**:
```bash
# Enumerate emails from a data breach list
for email in $(cat leaked_emails.txt); do
  response=$(curl -s -X POST http://target.com/api/login \
    -H "Content-Type: application/json" \
    -d "{\"email\":\"$email\",\"password\":\"test\"}")

  if [[ $response == *"Incorrect password"* ]]; then
    echo "VALID: $email exists in the system"
  fi
done
```

**Why This Is Dangerous**:
- Attackers can verify which emails are registered (pre-attack reconnaissance)
- Enables targeted credential stuffing using passwords from other breaches
- Facilitates spear-phishing by confirming target uses this service
- Timing differences in database lookups can also leak information

**SECURE VERSION**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const db = require('./database');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());

// SECURITY: Rate limiting prevents brute-force enumeration
const loginLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 attempts per window
  message: { error: 'Too many login attempts. Please try again later.' },
  standardHeaders: true,
  legacyHeaders: false
});

// SECURITY: Generic error message constant
const GENERIC_AUTH_ERROR = 'Invalid email or password';

app.post('/api/login', loginLimiter, async (req, res) => {
  const { email, password } = req.body;

  // SECURITY: Input validation
  if (!email || !password) {
    return res.status(400).json({ error: 'Email and password are required' });
  }

  try {
    const user = await db.query(
      'SELECT id, email, password_hash FROM users WHERE email = $1',
      [email]
    );

    // SECURITY: Always perform password comparison to prevent timing attacks
    // Use a dummy hash if user doesn't exist
    const dummyHash = '$2b$10$N9qo8uLOickgx2ZMRZoMyeIjZAgcfl7p92ldGxad68LJZdL17lhWy';
    const hashToCompare = user.rows.length > 0 
      ? user.rows[0].password_hash 
      : dummyHash;

    const validPassword = await bcrypt.compare(password, hashToCompare);

    // SECURITY: Generic error for BOTH invalid user AND invalid password
    if (!user.rows.length || !validPassword) {
      return res.status(401).json({ error: GENERIC_AUTH_ERROR });
    }

    // Login successful
    res.json({ token: generateToken(user.rows[0]) });

  } catch (error) {
    console.error('Login error:', error);
    res.status(401).json({ error: GENERIC_AUTH_ERROR });
  }
});
```

**Key Security Controls**:
- **Generic error messages**: Same response for invalid email or password prevents enumeration
- **Constant-time comparison**: Always run bcrypt.compare() even if user doesn't exist to prevent timing attacks
- **Rate limiting**: Slows down automated enumeration attempts
- **Input validation**: Rejects malformed requests early

Excellent security thinking! Password reset and registration are often overlooked enumeration vectors. Let me show you a comprehensive production-ready approach that handles all three flows securely.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');
const { body, validationResult } = require('express-validator');
const winston = require('winston');

const app = express();
app.use(express.json());

// Security logger for audit trail
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// Constants for consistent responses
const AUTH_MESSAGES = {
  LOGIN_FAILED: 'Invalid email or password',
  RESET_SENT: 'If an account exists with this email, you will receive a password reset link',
  REGISTER_SUCCESS: 'Registration successful. Please check your email to verify your account.'
};

// Configurable rate limiters per endpoint
const createLimiter = (maxAttempts, windowMinutes) => rateLimit({
  windowMs: windowMinutes * 60 * 1000,
  max: maxAttempts,
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    securityLogger.warn({
      event: 'rate_limit_exceeded',
      ip: req.ip,
      endpoint: req.path,
      userAgent: req.get('User-Agent')
    });
    res.status(429).json({ error: 'Too many requests. Please try again later.' });
  }
});

const loginLimiter = createLimiter(5, 15);
const resetLimiter = createLimiter(3, 60);
const registerLimiter = createLimiter(3, 60);

// Input validation middleware
const validateEmail = body('email').isEmail().normalizeEmail();
const validatePassword = body('password').isLength({ min: 12 })
  .matches(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])/);

// SECURE LOGIN - Prevents enumeration via timing and response analysis
app.post('/api/login', 
  loginLimiter,
  validateEmail,
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(401).json({ error: AUTH_MESSAGES.LOGIN_FAILED });
    }

    const { email, password } = req.body;
    const startTime = Date.now();

    try {
      const user = await db.query(
        'SELECT id, email, password_hash, failed_attempts, locked_until FROM users WHERE email = $1',
        [email]
      );

      // Check account lockout
      if (user.rows[0]?.locked_until && new Date(user.rows[0].locked_until) > new Date()) {
        // Don't reveal lockout - use generic message
        await artificialDelay(startTime, 500);
        return res.status(401).json({ error: AUTH_MESSAGES.LOGIN_FAILED });
      }

      // Always compare against a hash (dummy if user doesn't exist)
      const dummyHash = '$2b$12$LQv3c1yqBWVHxkd0LHAkCOYz6TtxMQJqhN8/X4.VTtYqG8SU8y5W.';
      const hashToCompare = user.rows[0]?.password_hash || dummyHash;

      const validPassword = await bcrypt.compare(password, hashToCompare);

      // Ensure consistent response time (prevent timing attacks)
      await artificialDelay(startTime, 500);

      if (!user.rows.length || !validPassword) {
        // Increment failed attempts if user exists
        if (user.rows.length) {
          await handleFailedAttempt(user.rows[0].id);
        }

        securityLogger.info({
          event: 'login_failed',
          email: hashEmail(email),
          ip: req.ip,
          reason: user.rows.length ? 'invalid_password' : 'unknown_user'
        });

        return res.status(401).json({ error: AUTH_MESSAGES.LOGIN_FAILED });
      }

      // Reset failed attempts on successful login
      await db.query(
        'UPDATE users SET failed_attempts = 0, locked_until = NULL WHERE id = $1',
        [user.rows[0].id]
      );

      securityLogger.info({
        event: 'login_success',
        userId: user.rows[0].id,
        ip: req.ip
      });

      const token = await generateSecureToken(user.rows[0]);
      res.json({ token });

    } catch (error) {
      securityLogger.error({ event: 'login_error', error: error.message });
      await artificialDelay(startTime, 500);
      res.status(401).json({ error: AUTH_MESSAGES.LOGIN_FAILED });
    }
});

// SECURE PASSWORD RESET - Same response whether email exists or not
app.post('/api/forgot-password',
  resetLimiter,
  validateEmail,
  async (req, res) => {
    const { email } = req.body;
    const startTime = Date.now();

    try {
      const user = await db.query(
        'SELECT id, email FROM users WHERE email = $1',
        [email]
      );

      // SECURITY: Only send email if user exists, but ALWAYS return success
      if (user.rows.length) {
        const resetToken = crypto.randomBytes(32).toString('hex');
        const tokenHash = crypto.createHash('sha256').update(resetToken).digest('hex');
        const expiresAt = new Date(Date.now() + 3600000); // 1 hour

        await db.query(
          'INSERT INTO password_resets (user_id, token_hash, expires_at) VALUES ($1, $2, $3)',
          [user.rows[0].id, tokenHash, expiresAt]
        );

        await sendPasswordResetEmail(email, resetToken);

        securityLogger.info({
          event: 'password_reset_requested',
          userId: user.rows[0].id,
          ip: req.ip
        });
      } else {
        // Log enumeration attempt (don't reveal to user)
        securityLogger.warn({
          event: 'password_reset_unknown_email',
          email: hashEmail(email),
          ip: req.ip
        });
      }

      // SECURITY: Consistent response time and message
      await artificialDelay(startTime, 1000);
      res.json({ message: AUTH_MESSAGES.RESET_SENT });

    } catch (error) {
      securityLogger.error({ event: 'reset_error', error: error.message });
      await artificialDelay(startTime, 1000);
      res.json({ message: AUTH_MESSAGES.RESET_SENT });
    }
});

// SECURE REGISTRATION - Prevents confirming existing accounts
app.post('/api/register',
  registerLimiter,
  validateEmail,
  validatePassword,
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ error: 'Invalid email or password format' });
    }

    const { email, password } = req.body;
    const startTime = Date.now();

    try {
      const existingUser = await db.query(
        'SELECT id FROM users WHERE email = $1',
        [email]
      );

      if (existingUser.rows.length) {
        // SECURITY: Send "already registered" email but return success
        await sendAlreadyRegisteredEmail(email);

        securityLogger.warn({
          event: 'registration_duplicate',
          email: hashEmail(email),
          ip: req.ip
        });
      } else {
        // Create new user
        const passwordHash = await bcrypt.hash(password, 12);
        const verificationToken = crypto.randomBytes(32).toString('hex');

        await db.query(
          `INSERT INTO users (email, password_hash, verification_token, created_at) 
           VALUES ($1, $2, $3, NOW())`,
          [email, passwordHash, verificationToken]
        );

        await sendVerificationEmail(email, verificationToken);

        securityLogger.info({
          event: 'registration_success',
          email: hashEmail(email),
          ip: req.ip
        });
      }

      // SECURITY: Same response whether account existed or not
      await artificialDelay(startTime, 1500);
      res.json({ message: AUTH_MESSAGES.REGISTER_SUCCESS });

    } catch (error) {
      securityLogger.error({ event: 'registration_error', error: error.message });
      await artificialDelay(startTime, 1500);
      res.json({ message: AUTH_MESSAGES.REGISTER_SUCCESS });
    }
});

// Helper: Add artificial delay to normalize response times
async function artificialDelay(startTime, targetMs) {
  const elapsed = Date.now() - startTime;
  const remaining = Math.max(0, targetMs - elapsed);
  if (remaining > 0) {
    await new Promise(resolve => setTimeout(resolve, remaining));
  }
}

// Helper: Hash email for secure logging (don't log raw emails)
function hashEmail(email) {
  return crypto.createHash('sha256').update(email.toLowerCase()).digest('hex').slice(0, 16);
}

// Helper: Handle failed login attempts with progressive lockout
async function handleFailedAttempt(userId) {
  const result = await db.query(
    'UPDATE users SET failed_attempts = failed_attempts + 1 WHERE id = $1 RETURNING failed_attempts',
    [userId]
  );

  const attempts = result.rows[0].failed_attempts;

  // Progressive lockout: 5 attempts = 15 min, 10 attempts = 1 hour
  if (attempts >= 10) {
    await db.query(
      'UPDATE users SET locked_until = NOW() + INTERVAL \'1 hour\' WHERE id = $1',
      [userId]
    );
  } else if (attempts >= 5) {
    await db.query(
      'UPDATE users SET locked_until = NOW() + INTERVAL \'15 minutes\' WHERE id = $1',
      [userId]
    );
  }
}
```

**Defense in Depth Layers**:

1. **Response Normalization**: Same message and HTTP status regardless of whether account exists
```javascript
// Always return this message for login failures
return res.status(401).json({ error: 'Invalid email or password' });
```

2. **Timing Attack Prevention**: Artificial delays ensure consistent response times
```javascript
const startTime = Date.now();
// ... process request ...
await artificialDelay(startTime, 500); // Always takes ~500ms
```

3. **Progressive Rate Limiting**: IP-based and account-based lockouts
```javascript
// After 5 failed attempts: 15 minute lockout
// After 10 failed attempts: 1 hour lockout
```

**Additional Protections**:
- **Secure logging**: Hash emails in logs to prevent secondary data leakage
- **Email notifications**: For existing accounts during registration, send "already registered" email rather than error
- **CAPTCHA integration**: Add after 3 failed attempts to stop automated tools
- **Honeypot accounts**: Create fake accounts to detect enumeration attacks
- **Behavioral analysis**: Monitor for patterns indicating enumeration (sequential emails, rapid requests)

Your concern about username enumeration is valid, but there's a subtle vulnerability many developers miss: timing attacks. Even if you return identical error messages, attackers can measure response times to determine if a username exists.

**VULNERABLE CODE**:

```java
import java.sql.*;
import javax.servlet.http.*;
import org.mindrot.jbcrypt.BCrypt;

public class LoginServlet extends HttpServlet {
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "secret123";

    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        String username = request.getParameter("username");
        String password = request.getParameter("password");

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT password_hash FROM users WHERE username = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, username);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                // TIMING LEAK: BCrypt comparison only happens for valid users
                String storedHash = rs.getString("password_hash");
                if (BCrypt.checkpw(password, storedHash)) {
                    request.getSession().setAttribute("user", username);
                    response.sendRedirect("/dashboard");
                    return;
                }
            }
            // Same error message but different execution time!
            response.sendError(401, "Invalid credentials");
        } catch (Exception e) {
            response.sendError(500, "Server error");
        }
    }
}
```

**Attack Payload**:
```bash
# Timing attack script measuring response times
for user in admin root test john.smith; do
  start=$(date +%s%N)
  curl -s -X POST http://target.com/login -d "username=$user&password=test123"
  end=$(date +%s%N)
  echo "$user: $((($end-$start)/1000000))ms"
done
# Output shows ~200ms for invalid users, ~350ms for valid users (BCrypt overhead)
```

**Why This Is Dangerous**:
- BCrypt.checkpw() takes ~100-300ms intentionally (cost factor), only executed for valid users
- Invalid usernames return immediately after database lookup (~5-10ms)
- Attackers can distinguish valid from invalid usernames with 95%+ accuracy
- Enables targeted credential stuffing attacks against confirmed accounts
- CVE-2023-20269 exploited this exact pattern in Cisco devices

**SECURE VERSION**:

```java
import java.sql.*;
import javax.servlet.http.*;
import org.mindrot.jbcrypt.BCrypt;
import java.security.SecureRandom;

public class SecureLoginServlet extends HttpServlet {
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "secret123";

    // Pre-computed dummy hash with same cost factor as real hashes
    // Generated once at startup: BCrypt.hashpw("dummy", BCrypt.gensalt(12))
    private static final String DUMMY_HASH = 
        "$2a$12$LQv3c1yqBWVHxkd0LHAkCOYz6TtxMQJqhN8/X4.G.3KsEkT7Z2KPe";

    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        String username = request.getParameter("username");
        String password = request.getParameter("password");

        if (username == null || password == null || 
            username.length() > 255 || password.length() > 128) {
            sendAuthFailure(response, "Invalid credentials");
            return;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT password_hash FROM users WHERE username = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, username);
            ResultSet rs = stmt.executeQuery();

            String hashToCheck;
            boolean userExists = rs.next();

            if (userExists) {
                hashToCheck = rs.getString("password_hash");
            } else {
                // CONSTANT TIME: Always perform BCrypt check with dummy hash
                hashToCheck = DUMMY_HASH;
            }

            // BCrypt comparison ALWAYS happens - same timing regardless of user existence
            boolean passwordValid = BCrypt.checkpw(password, hashToCheck);

            if (userExists && passwordValid) {
                request.getSession().setAttribute("user", username);
                response.sendRedirect("/dashboard");
                return;
            }

            sendAuthFailure(response, "Invalid credentials");
        } catch (Exception e) {
            // Log internally but don't leak details
            sendAuthFailure(response, "Invalid credentials");
        }
    }

    private void sendAuthFailure(HttpServletResponse response, String message) {
        try {
            response.sendError(401, message);
        } catch (Exception ignored) {}
    }
}
```

**Key Security Controls**:
- **Constant-time execution**: BCrypt comparison always runs, even for invalid usernames
- **Dummy hash with matching cost**: Same computational overhead for all requests
- **Generic error messages**: No distinction between invalid username and invalid password
- **Input validation**: Prevents DoS via extremely long inputs

You're right to be concerned. Advanced attackers use statistical analysis with hundreds or thousands of requests to detect even microsecond-level timing differences. Production systems need multiple layers of defense including constant-time comparisons at every level, artificial timing jitter, and comprehensive rate limiting.

**PRODUCTION PATTERN**:

```java
import java.sql.*;
import javax.servlet.http.*;
import org.mindrot.jbcrypt.BCrypt;
import java.security.SecureRandom;
import java.security.MessageDigest;
import java.util.concurrent.*;
import java.util.logging.Logger;
import io.github.bucket4j.*;
import java.time.Duration;

public class ProductionLoginServlet extends HttpServlet {
    private static final Logger auditLog = Logger.getLogger("security.audit");
    private static final Logger appLog = Logger.getLogger("application");
    private static final SecureRandom secureRandom = new SecureRandom();

    private static final String DUMMY_HASH = 
        "$2a$12$LQv3c1yqBWVHxkd0LHAkCOYz6TtxMQJqhN8/X4.G.3KsEkT7Z2KPe";

    // Rate limiter: 5 attempts per IP per minute
    private final ConcurrentHashMap<String, Bucket> ipBuckets = new ConcurrentHashMap<>();
    // Rate limiter: 10 attempts per username per hour
    private final ConcurrentHashMap<String, Bucket> userBuckets = new ConcurrentHashMap<>();

    // Minimum response time to mask all variations (500ms)
    private static final long MIN_RESPONSE_TIME_MS = 500;
    // Maximum jitter to add (100ms)
    private static final long MAX_JITTER_MS = 100;

    private DataSource dataSource; // Injected connection pool

    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        long startTime = System.nanoTime();
        String clientIp = getClientIp(request);
        String username = request.getParameter("username");
        String password = request.getParameter("password");
        String requestId = generateRequestId();

        try {
            // Layer 1: IP-based rate limiting
            if (!checkIpRateLimit(clientIp)) {
                auditLog.warning(String.format(
                    "[%s] Rate limit exceeded for IP: %s", requestId, clientIp));
                enforceMinimumResponseTime(startTime);
                response.sendError(429, "Too many requests");
                return;
            }

            // Layer 2: Input validation with constant-time length check
            if (!isValidInput(username, password)) {
                auditLog.info(String.format(
                    "[%s] Invalid input format from IP: %s", requestId, clientIp));
                enforceMinimumResponseTime(startTime);
                sendAuthFailure(response);
                return;
            }

            // Layer 3: Username-based rate limiting (after validation)
            String normalizedUsername = normalizeUsername(username);
            if (!checkUsernameRateLimit(normalizedUsername)) {
                auditLog.warning(String.format(
                    "[%s] Rate limit exceeded for user: %s from IP: %s",
                    requestId, maskUsername(normalizedUsername), clientIp));
                enforceMinimumResponseTime(startTime);
                sendAuthFailure(response);
                return;
            }

            // Layer 4: Authenticate with constant-time operations
            AuthResult result = authenticateUser(normalizedUsername, password);

            // Layer 5: Enforce minimum response time with jitter
            enforceMinimumResponseTime(startTime);

            if (result.isSuccess()) {
                auditLog.info(String.format(
                    "[%s] Successful login for user: %s from IP: %s",
                    requestId, maskUsername(normalizedUsername), clientIp));

                // Regenerate session ID to prevent session fixation
                request.getSession().invalidate();
                HttpSession newSession = request.getSession(true);
                newSession.setAttribute("user", normalizedUsername);
                newSession.setAttribute("loginTime", System.currentTimeMillis());
                newSession.setAttribute("loginIp", clientIp);
                newSession.setMaxInactiveInterval(1800); // 30 minutes

                response.sendRedirect("/dashboard");
            } else {
                auditLog.info(String.format(
                    "[%s] Failed login attempt for user: %s from IP: %s",
                    requestId, maskUsername(normalizedUsername), clientIp));
                sendAuthFailure(response);
            }

        } catch (Exception e) {
            appLog.severe(String.format("[%s] Login error: %s", requestId, e.getMessage()));
            enforceMinimumResponseTime(startTime);
            sendAuthFailure(response);
        }
    }

    private AuthResult authenticateUser(String username, String password) {
        String hashToCheck = DUMMY_HASH;
        boolean userExists = false;

        try (Connection conn = dataSource.getConnection()) {
            String sql = "SELECT password_hash, account_locked, failed_attempts " +
                        "FROM users WHERE username = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, username);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                userExists = true;
                boolean accountLocked = rs.getBoolean("account_locked");
                int failedAttempts = rs.getInt("failed_attempts");

                if (accountLocked || failedAttempts >= 5) {
                    // Still perform BCrypt check to maintain constant timing
                    BCrypt.checkpw(password, DUMMY_HASH);
                    return AuthResult.accountLocked();
                }
                hashToCheck = rs.getString("password_hash");
            }

            // CONSTANT TIME: Always perform BCrypt check
            boolean passwordValid = BCrypt.checkpw(password, hashToCheck);

            if (userExists && passwordValid) {
                resetFailedAttempts(conn, username);
                return AuthResult.success();
            } else if (userExists) {
                incrementFailedAttempts(conn, username);
            }

            return AuthResult.failure();

        } catch (SQLException e) {
            // Perform BCrypt check to maintain timing even on error
            BCrypt.checkpw(password, DUMMY_HASH);
            return AuthResult.failure();
        }
    }

    private void enforceMinimumResponseTime(long startTimeNanos) {
        long elapsedMs = (System.nanoTime() - startTimeNanos) / 1_000_000;
        long jitter = secureRandom.nextLong(MAX_JITTER_MS);
        long targetTime = MIN_RESPONSE_TIME_MS + jitter;
        long sleepTime = targetTime - elapsedMs;

        if (sleepTime > 0) {
            try {
                Thread.sleep(sleepTime);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }
    }

    private boolean isValidInput(String username, String password) {
        if (username == null || password == null) return false;
        // Use constant-time length comparison
        int usernameLen = username.length();
        int passwordLen = password.length();
        boolean usernameValid = (usernameLen >= 3) & (usernameLen <= 64);
        boolean passwordValid = (passwordLen >= 8) & (passwordLen <= 128);
        return usernameValid & passwordValid; // Bitwise AND for constant time
    }

    private Bucket createIpBucket() {
        return Bucket.builder()
            .addLimit(Bandwidth.classic(5, Refill.intervally(5, Duration.ofMinutes(1))))
            .build();
    }

    private Bucket createUserBucket() {
        return Bucket.builder()
            .addLimit(Bandwidth.classic(10, Refill.intervally(10, Duration.ofHours(1))))
            .build();
    }

    private boolean checkIpRateLimit(String ip) {
        Bucket bucket = ipBuckets.computeIfAbsent(ip, k -> createIpBucket());
        return bucket.tryConsume(1);
    }

    private boolean checkUsernameRateLimit(String username) {
        Bucket bucket = userBuckets.computeIfAbsent(username, k -> createUserBucket());
        return bucket.tryConsume(1);
    }

    private String normalizeUsername(String username) {
        return username.toLowerCase().trim();
    }

    private String maskUsername(String username) {
        if (username.length() <= 2) return "**";
        return username.charAt(0) + "***" + username.charAt(username.length() - 1);
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
