        // SECURE: Always perform password verification to maintain constant time
        $hashToCheck = $user ? $user['password_hash'] : $this->fakePasswordHash;
        $passwordValid = password_verify($password, $hashToCheck);

        // SECURE: Only succeed if BOTH user exists AND password is correct
        if ($user && $passwordValid) {
            session_regenerate_id(true);
            $_SESSION['user_id'] = $user['id'];
            return true;
