```csharp
using System;
using System.Security.Cryptography;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Identity;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Caching.Distributed;
using System.Text.Json;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class SecureAuthController : ControllerBase
    {
        private readonly UserManager<ApplicationUser> _userManager;
        private readonly SignInManager<ApplicationUser> _signInManager;
        private readonly ILogger<SecureAuthController> _logger;
        private readonly IDistributedCache _cache;
        private readonly IEmailService _emailService;
        private readonly ISecurityMetricsService _metrics;

        private const string GenericAuthError = "Invalid email or password";
        private const string GenericResetMessage = "If an account exists with this email, you will receive a password reset link";
        private const int MaxLoginAttemptsPerIp = 10;
        private const int MaxResetRequestsPerIp = 3;
        private const int RateLimitWindowMinutes = 15;

        public SecureAuthController(
            UserManager<ApplicationUser> userManager,
            SignInManager<ApplicationUser> signInManager,
            ILogger<SecureAuthController> logger,
            IDistributedCache cache,
            IEmailService emailService,
            ISecurityMetricsService metrics)
        {
            _userManager = userManager;
            _signInManager = signInManager;
            _logger = logger;
            _cache = cache;
            _emailService = emailService;
            _metrics = metrics;
        }

        [HttpPost("login")]
        public async Task<IActionResult> Login([FromBody] LoginRequest request)
        {
            var clientIp = GetClientIpAddress();
            var requestId = Guid.NewGuid().ToString();

            // Rate limiting check
            if (await IsRateLimited(clientIp, "login", MaxLoginAttemptsPerIp))
            {
                _logger.LogWarning(
                    "Rate limit exceeded for login. IP: {IP}, RequestId: {RequestId}",
                    HashIp(clientIp), requestId);
                _metrics.IncrementCounter("auth.ratelimit.exceeded", new[] { "endpoint:login" });

                // SECURE: Same error message, add small delay
                await AddRandomDelay();
                return Unauthorized(new { error = GenericAuthError, requestId });
            }

            await IncrementRateLimitCounter(clientIp, "login");

            var startTime = DateTime.UtcNow;
            var user = await _userManager.FindByEmailAsync(request.Email?.ToLowerInvariant());

            bool authSuccess = false;
            string failureReason = "unknown";

            if (user == null)
            {
                await SimulatePasswordVerification();
                failureReason = "user_not_found";
            }
            else
            {
                var result = await _signInManager.CheckPasswordSignInAsync(
                    user, request.Password, lockoutOnFailure: true);

                if (result.Succeeded)
                {
                    authSuccess = true;
                    await ResetRateLimitCounter(clientIp, "login");
                }
                else if (result.IsLockedOut)
                {
                    failureReason = "account_locked";
                }
                else if (result.IsNotAllowed)
                {
                    failureReason = "not_allowed";
                }
                else
                {
                    failureReason = "invalid_password";
                }
            }

            // Normalize response time (250-350ms)
            await NormalizeResponseTime(startTime, TimeSpan.FromMilliseconds(300));

            // Security event logging
            await LogSecurityEvent(new SecurityEvent
            {
                EventType = authSuccess ? "LOGIN_SUCCESS" : "LOGIN_FAILURE",
                RequestId = requestId,
                IpAddressHash = HashIp(clientIp),
                UserIdHash = user != null ? HashUserId(user.Id) : null,
                FailureReason = authSuccess ? null : failureReason,
                Timestamp = DateTime.UtcNow,
                UserAgent = Request.Headers["User-Agent"].ToString()
            });

            if (!authSuccess)
            {
                _metrics.IncrementCounter("auth.login.failed", 
                    new[] { $"reason:{failureReason}" });
                return Unauthorized(new { error = GenericAuthError, requestId });
            }

            _metrics.IncrementCounter("auth.login.success");
            return Ok(new { token = await GenerateJwtToken(user), requestId });
        }

        [HttpPost("forgot-password")]
        public async Task<IActionResult> ForgotPassword([FromBody] ForgotPasswordRequest request)
        {
            var clientIp = GetClientIpAddress();
            var requestId = Guid.NewGuid().ToString();

            // Stricter rate limiting for password reset
            if (await IsRateLimited(clientIp, "reset", MaxResetRequestsPerIp))
            {
                _logger.LogWarning(
                    "Rate limit exceeded for password reset. IP: {IP}, RequestId: {RequestId}",
                    HashIp(clientIp), requestId);
                _metrics.IncrementCounter("auth.ratelimit.exceeded", 
                    new[] { "endpoint:forgot-password" });

                await AddRandomDelay();
                // SECURE: Always return success message
                return Ok(new { message = GenericResetMessage, requestId });
            }

            await IncrementRateLimitCounter(clientIp, "reset");

            var startTime = DateTime.UtcNow;
            var user = await _userManager.FindByEmailAsync(request.Email?.ToLowerInvariant());

            if (user != null && await _userManager.IsEmailConfirmedAsync(user))
            {
                var token = await _userManager.GeneratePasswordResetTokenAsync(user);
                var resetLink = GenerateSecureResetLink(user.Id, token);

                // Send email asynchronously (don't wait)
                _ = _emailService.SendPasswordResetEmailAsync(user.Email, resetLink);

                await LogSecurityEvent(new SecurityEvent
                {
                    EventType = "PASSWORD_RESET_REQUESTED",
                    RequestId = requestId,
                    IpAddressHash = HashIp(clientIp),
                    UserIdHash = HashUserId(user.Id),
                    Timestamp = DateTime.UtcNow
                });
            }
            else
            {
                // Log attempt for non-existent users (for security monitoring)
                await LogSecurityEvent(new SecurityEvent
                {
                    EventType = "PASSWORD_RESET_NONEXISTENT",
                    RequestId = requestId,
                    IpAddressHash = HashIp(clientIp),
                    EmailHash = HashEmail(request.Email),
                    Timestamp = DateTime.UtcNow
                });
            }

            // Normalize response time regardless of user existence
            await NormalizeResponseTime(startTime, TimeSpan.FromMilliseconds(500));

            // SECURE: Always return same response
            return Ok(new { message = GenericResetMessage, requestId });
        }

        [HttpPost("check-email")]
        public async Task<IActionResult> CheckEmailAvailability([FromBody] CheckEmailRequest request)
        {
            // SECURE: Registration email checks should require CAPTCHA
            if (!await VerifyCaptcha(request.CaptchaToken))
            {
                return BadRequest(new { error = "Invalid CAPTCHA" });
            }

            var startTime = DateTime.UtcNow;
            var exists = await _userManager.FindByEmailAsync(request.Email?.ToLowerInvariant()) != null;

            await NormalizeResponseTime(startTime, TimeSpan.FromMilliseconds(200));

            // SECURE: Only allow during registration flow with valid CAPTCHA
            return Ok(new { available = !exists });
        }

        #region Security Helpers

        private async Task SimulatePasswordVerification()
        {
            // Simulate bcrypt timing (100-150ms)
            using var rng = RandomNumberGenerator.Create();
            var bytes = new byte[4];
            rng.GetBytes(bytes);
            var delay = 100 + (BitConverter.ToUInt32(bytes, 0) % 50);
            await Task.Delay((int)delay);
        }

        private async Task NormalizeResponseTime(DateTime startTime, TimeSpan targetDuration)
        {
            var elapsed = DateTime.UtcNow - startTime;
            if (elapsed < targetDuration)
            {
                var remaining = targetDuration - elapsed;
                // Add jitter (-10% to +10%)
                using var rng = RandomNumberGenerator.Create();
                var bytes = new byte[4];
                rng.GetBytes(bytes);
                var jitter = (BitConverter.ToInt32(bytes, 0) % 20 - 10) / 100.0;
                var adjustedDelay = remaining.TotalMilliseconds * (1 + jitter);
                await Task.Delay(TimeSpan.FromMilliseconds(Math.Max(0, adjustedDelay)));
            }
        }

        private async Task AddRandomDelay()
        {
            using var rng = RandomNumberGenerator.Create();
            var bytes = new byte[4];
            rng.GetBytes(bytes);
            var delay = 200 + (BitConverter.ToUInt32(bytes, 0) % 300);
            await Task.Delay((int)delay);
        }

        private async Task<bool> IsRateLimited(string clientIp, string action, int maxAttempts)
        {
            var key = $"ratelimit:{action}:{HashIp(clientIp)}";
            var countStr = await _cache.GetStringAsync(key);
            return int.TryParse(countStr, out int count) && count >= maxAttempts;
        }

        private async Task IncrementRateLimitCounter(string clientIp, string action)
        {
            var key = $"ratelimit:{action}:{HashIp(clientIp)}";
            var countStr = await _cache.GetStringAsync(key);
            var count = int.TryParse(countStr, out int c) ? c + 1 : 1;
            await _cache.SetStringAsync(key, count.ToString(),
                new DistributedCacheEntryOptions
                {
                    AbsoluteExpirationRelativeToNow = TimeSpan.FromMinutes(RateLimitWindowMinutes)
                });
        }

        private async Task ResetRateLimitCounter(string clientIp, string action)
        {
            var key = $"ratelimit:{action}:{HashIp(clientIp)}";
            await _cache.RemoveAsync(key);
        }

        private string HashIp(string ip)
        {
            using var sha = SHA256.Create();
            var hash = sha.ComputeHash(System.Text.Encoding.UTF8.GetBytes(ip + "_ip_salt_xyz"));
            return Convert.ToBase64String(hash).Substring(0, 16);
        }

        private string HashUserId(string userId) =>
            Convert.ToBase64String(SHA256.HashData(
                System.Text.Encoding.UTF8.GetBytes(userId))).Substring(0, 16);

        private string HashEmail(string email) =>
            Convert.ToBase64String(SHA256.HashData(
                System.Text.Encoding.UTF8.GetBytes(email?.ToLowerInvariant() ?? ""))).Substring(0, 16);

        private string GetClientIpAddress() =>
            HttpContext.Connection.RemoteIpAddress?.ToString() ?? "unknown";

        #endregion
    }

    public class SecurityEvent
    {
        public string EventType { get; set; }
        public string RequestId { get; set; }
        public string IpAddressHash { get; set; }
        public string UserIdHash { get; set; }
        public string EmailHash { get; set; }
        public string FailureReason { get; set; }
        public DateTime Timestamp { get; set; }
        public string UserAgent { get; set; }
    }
}
