```java
import java.sql.*;
import javax.servlet.http.*;
import javax.servlet.annotation.*;
import java.io.IOException;
import java.security.SecureRandom;
import org.mindrot.jbcrypt.BCrypt;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@WebServlet("/login")
public class SecureLoginServlet extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureLoginServlet.class);
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password123";

    // Fake hash for non-existent users to prevent timing attacks
    private static final String DUMMY_HASH = BCrypt.hashpw("dummy", BCrypt.gensalt(12));

    // Generic error message - same for all failure cases
    private static final String LOGIN_FAILED_MSG = "{\"error\": \"Invalid username or password\"}";

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws IOException {
        String username = request.getParameter("username");
        String password = request.getParameter("password");
        String clientIp = getClientIP(request);

        // Input validation
        if (username == null || password == null || 
            username.length() > 100 || password.length() > 128) {
            // Same response as invalid credentials
            simulateHashCheck();
            response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
            response.getWriter().write(LOGIN_FAILED_MSG);
            return;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT id, password_hash, account_locked FROM users WHERE username = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, username);
            ResultSet rs = stmt.executeQuery();

            String storedHash = DUMMY_HASH; // Default to dummy hash
            Long userId = null;
            boolean accountLocked = false;
            boolean userExists = false;

            if (rs.next()) {
                userExists = true;
                userId = rs.getLong("id");
                storedHash = rs.getString("password_hash");
                accountLocked = rs.getBoolean("account_locked");
            }

            // SECURE: Always perform hash check (constant time operation)
            // Even for non-existent users, we check against dummy hash
            boolean passwordValid = BCrypt.checkpw(password, storedHash);

            if (!userExists || !passwordValid || accountLocked) {
                // Log failed attempt without revealing which condition failed
                logger.warn("Failed login attempt for user input from IP: {}", clientIp);

                if (userExists && !accountLocked) {
                    incrementFailedAttempts(conn, userId);
                }

                // SECURE: Generic error message for ALL failure types
                response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
                response.getWriter().write(LOGIN_FAILED_MSG);
                return;
            }

            // Successful login
            resetFailedAttempts(conn, userId);
            HttpSession session = request.getSession(true);
            session.setAttribute("userId", userId);
            session.setAttribute("username", username);

            logger.info("Successful login for user ID: {} from IP: {}", userId, clientIp);
            response.getWriter().write("{\"success\": true}");

        } catch (SQLException e) {
            logger.error("Database error during login", e);
            response.setStatus(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
            response.getWriter().write("{\"error\": \"An error occurred. Please try again.\"}");
        }
    }

    private void simulateHashCheck() {
        // Simulate bcrypt timing for invalid inputs
        BCrypt.checkpw("dummy", DUMMY_HASH);
    }

    private String getClientIP(HttpServletRequest request) {
        String ip = request.getHeader("X-Forwarded-For");
        return (ip != null) ? ip.split(",")[0].trim() : request.getRemoteAddr();
    }

    private void incrementFailedAttempts(Connection conn, Long userId) throws SQLException {
        String sql = "UPDATE users SET failed_attempts = failed_attempts + 1, " +
                     "account_locked = CASE WHEN failed_attempts >= 4 THEN true ELSE false END " +
                     "WHERE id = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setLong(1, userId);
        stmt.executeUpdate();
    }

    private void resetFailedAttempts(Connection conn, Long userId) throws SQLException {
        String sql = "UPDATE users SET failed_attempts = 0 WHERE id = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setLong(1, userId);
        stmt.executeUpdate();
    }
}
```

**Key Security Controls**:
- **Generic error messages**: Same "Invalid username or password" for all failure types prevents enumeration
- **Constant-time operations**: BCrypt check runs even for non-existent users, preventing timing attacks
- **Dummy hash comparison**: Non-existent users still trigger password hash verification
- **Secure logging**: Logs IP addresses without revealing which credential was invalid

Excellent question! Password reset and registration are the most common account enumeration vectors. Many developers secure the login page but forget these endpoints reveal user existence through different messages or timing.

**PRODUCTION PATTERN**:

```java
import java.sql.*;
import javax.servlet.http.*;
import javax.servlet.annotation.*;
import java.io.IOException;
import java.security.SecureRandom;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.Base64;
import java.util.concurrent.*;
import org.mindrot.jbcrypt.BCrypt;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@WebServlet("/api/auth/*")
public class SecureAuthController extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureAuthController.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    private static final String DB_URL = System.getenv("DATABASE_URL");
    private static final String DB_USER = System.getenv("DATABASE_USER");
    private static final String DB_PASS = System.getenv("DATABASE_PASSWORD");

    // Rate limiting: IP -> (count, windowStart)
    private static final ConcurrentHashMap<String, RateLimitEntry> rateLimits = new ConcurrentHashMap<>();
    private static final int MAX_REQUESTS_PER_MINUTE = 5;

    // Simulated async delay range (milliseconds)
    private static final int MIN_RESPONSE_DELAY = 800;
    private static final int MAX_RESPONSE_DELAY = 1200;

    private final SecureRandom secureRandom = new SecureRandom();
    private final EmailService emailService = new EmailService();

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws IOException {
        String path = request.getPathInfo();
        String clientIp = getClientIP(request);

        // Rate limiting check
        if (isRateLimited(clientIp)) {
            auditLogger.warn("Rate limit exceeded for IP: {}", clientIp);
            response.setStatus(429);
            response.getWriter().write("{\"error\": \"Too many requests. Please try again later.\"}");
            return;
        }

        switch (path) {
            case "/password-reset":
                handlePasswordReset(request, response, clientIp);
                break;
            case "/register":
                handleRegistration(request, response, clientIp);
                break;
            case "/check-username":
                handleUsernameCheck(request, response, clientIp);
                break;
            default:
                response.setStatus(404);
        }
    }

    /**
     * SECURE PASSWORD RESET - Prevents enumeration through:
     * 1. Identical response messages regardless of account existence
     * 2. Consistent response timing
     * 3. No email disclosure
     */
    private void handlePasswordReset(HttpServletRequest request, 
                                      HttpServletResponse response, 
                                      String clientIp) throws IOException {
        String email = request.getParameter("email");

        // Validate email format
        if (email == null || !isValidEmail(email)) {
            addRandomDelay();
            sendGenericResetResponse(response);
            return;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT id, email, account_locked FROM users WHERE LOWER(email) = LOWER(?)";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, email);
            ResultSet rs = stmt.executeQuery();

            boolean userExists = rs.next();
            Long userId = userExists ? rs.getLong("id") : null;
            boolean accountLocked = userExists && rs.getBoolean("account_locked");

            if (userExists && !accountLocked) {
                // Generate secure reset token
                String token = generateSecureToken();
                Instant expiry = Instant.now().plus(1, ChronoUnit.HOURS);

                // Store token hash (never store plain tokens)
                String tokenHash = BCrypt.hashpw(token, BCrypt.gensalt(10));
                storeResetToken(conn, userId, tokenHash, expiry);

                // Send email asynchronously (don't block response)
                CompletableFuture.runAsync(() -> 
                    emailService.sendPasswordResetEmail(email, token)
                );

                auditLogger.info("Password reset requested for user ID: {} from IP: {}", 
                                 userId, clientIp);
            } else {
                // Log attempt for non-existent email (for security monitoring)
                auditLogger.info("Password reset attempted for non-existent email from IP: {}", 
                                 clientIp);
            }

            // CRITICAL: Add random delay to prevent timing attacks
            addRandomDelay();

            // CRITICAL: Same response regardless of account existence
            sendGenericResetResponse(response);

        } catch (SQLException e) {
            logger.error("Database error during password reset", e);
            addRandomDelay();
            sendGenericResetResponse(response);
        }
    }

    /**
     * SECURE REGISTRATION - Prevents enumeration through:
     * 1. Delayed/async email verification
     * 2. No immediate "email taken" disclosure
     * 3. Consistent response for all cases
     */
    private void handleRegistration(HttpServletRequest request, 
                                     HttpServletResponse response, 
                                     String clientIp) throws IOException {
        String email = request.getParameter("email");
        String username = request.getParameter("username");
        String password = request.getParameter("password");

        // Validate inputs
        if (!isValidEmail(email) || !isValidUsername(username) || !isStrongPassword(password)) {
            addRandomDelay();
            response.getWriter().write(
                "{\"message\": \"Please check your email to complete registration.\"}");
            return;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // Check if user exists (but don't reveal this)
            boolean emailExists = checkEmailExists(conn, email);
            boolean usernameExists = checkUsernameExists(conn, username);

            if (emailExists || usernameExists) {
                // User exists - send email notification instead of revealing
                if (emailExists) {
                    CompletableFuture.runAsync(() -> 
                        emailService.sendAccountExistsNotification(email)
                    );
                }
                auditLogger.info("Registration attempt for existing account from IP: {}", clientIp);
            } else {
                // Create pending registration
                String verificationToken = generateSecureToken();
                createPendingRegistration(conn, email, username, password, verificationToken);

                CompletableFuture.runAsync(() -> 
                    emailService.sendVerificationEmail(email, verificationToken)
                );

                auditLogger.info("New registration initiated from IP: {}", clientIp);
            }

            addRandomDelay();

            // CRITICAL: Identical response for all cases
            response.getWriter().write(
                "{\"message\": \"Please check your email to complete registration.\"}");

        } catch (SQLException e) {
            logger.error("Database error during registration", e);
            addRandomDelay();
            response.getWriter().write(
                "{\"message\": \"Please check your email to complete registration.\"}");
        }
    }

    /**
     * SECURE USERNAME AVAILABILITY CHECK
     * Some UX requires this - use CAPTCHA and rate limiting
     */
    private void handleUsernameCheck(HttpServletRequest request, 
                                      HttpServletResponse response, 
                                      String clientIp) throws IOException {
        String username = request.getParameter("username");
        String captchaToken = request.getParameter("captcha");

        // Require CAPTCHA for this sensitive operation
        if (!verifyCaptcha(captchaToken, clientIp)) {
            response.setStatus(HttpServletResponse.SC_FORBIDDEN);
            response.getWriter().write("{\"error\": \"Invalid CAPTCHA\"}");
            return;
        }

        // Stricter rate limit for this endpoint
        if (getUsernameCheckCount(clientIp) > 10) {
            response.setStatus(429);
            response.getWriter().write("{\"error\": \"Too many checks. Please try again later.\"}");
            return;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            boolean exists = checkUsernameExists(conn, username);

            // Only reveal for registration flow with CAPTCHA protection
            addRandomDelay();
            response.getWriter().write(
                String.format("{\"available\": %s}", !exists));

            incrementUsernameCheckCount(clientIp);

        } catch (SQLException e) {
            logger.error("Database error during username check", e);
            response.getWriter().write("{\"available\": false}");
        }
    }

    private void sendGenericResetResponse(HttpServletResponse response) throws IOException {
        response.getWriter().write(
            "{\"message\": \"If an account exists with this email, you will receive reset instructions.\"}");
    }

    private void addRandomDelay() {
        try {
            int delay = MIN_RESPONSE_DELAY + 
                        secureRandom.nextInt(MAX_RESPONSE_DELAY - MIN_RESPONSE_DELAY);
            Thread.sleep(delay);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }

    private String generateSecureToken() {
        byte[] tokenBytes = new byte[32];
        secureRandom.nextBytes(tokenBytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(tokenBytes);
    }

    private boolean isRateLimited(String clientIp) {
        RateLimitEntry entry = rateLimits.compute(clientIp, (ip, existing) -> {
            long now = System.currentTimeMillis();
            if (existing == null || now - existing.windowStart > 60000) {
                return new RateLimitEntry(1, now);
            }
            existing.count++;
            return existing;
        });
        return entry.count > MAX_REQUESTS_PER_MINUTE;
    }

    private boolean isValidEmail(String email) {
        return email != null && 
               email.matches("^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+$") &&
               email.length() <= 255;
    }

    private boolean isValidUsername(String username) {
        return username != null && 
               username.matches("^[a-zA-Z0-9_-]{3,30}$");
    }

    private boolean isStrongPassword(String password) {
        return password != null && 
               password.length() >= 12 &&
               password.matches(".*[A-Z].*") &&
               password.matches(".*[a-z].*") &&
               password.matches(".*[0-9].*");
    }

    private boolean checkEmailExists(Connection conn, String email) throws SQLException {
        String sql = "SELECT 1 FROM users WHERE LOWER(email) = LOWER(?)";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setString(1, email);
        return stmt.executeQuery().next();
    }

    private boolean checkUsernameExists(Connection conn, String username) throws SQLException {
        String sql = "SELECT 1 FROM users WHERE LOWER(username) = LOWER(?)";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setString(1, username);
        return stmt.executeQuery().next();
    }

    private void storeResetToken(Connection conn, Long userId, String tokenHash, Instant expiry) 
            throws SQLException {
        // Invalidate existing tokens first
        String deleteSql = "DELETE FROM password_reset_tokens WHERE user_id = ?";
        PreparedStatement deleteStmt = conn.prepareStatement(deleteSql);
        deleteStmt.setLong(1, userId);
        deleteStmt.executeUpdate();

        String insertSql = "INSERT INTO password_reset_tokens (user_id, token_hash, expires_at) VALUES (?, ?, ?)";
        PreparedStatement insertStmt = conn.prepareStatement(insertSql);
        insertStmt.setLong(1, userId);
        insertStmt.setString(2, tokenHash);
        insertStmt.setTimestamp(3, Timestamp.from(expiry));
        insertStmt.executeUpdate();
    }

    private void createPendingRegistration(Connection conn, String email, String username, 
                                            String password, String verificationToken) 
            throws SQLException {
